awk_script='#!/usr/bin/awk -f
BEGIN { found=0 }
{
  # Remove leading whitespace
  line = $0
  sub(/^[ \t]+/, "", line)

  # Check if line contains minlen (with optional leading # and whitespace)
  if (line ~ /^[[:space:]]*#[[:space:]]*minlen[[:space:]]*=/ || line ~ /^[[:space:]]*minlen[[:space:]]*=/) {
    print "minlen = 14"
    found=1
  } else {
    print $0
  }
}
END { if (!found) print "minlen = 14" }' && echo "$awk_script" > /tmp/set_minlen.awk

